package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.asn.event.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.time.*;
@RestController @RequestMapping("/internal/supplier/v1/tms/asns") public class TmsAsnOpenApiController{private final TmsAsnEventConsumerApplicationService service;public TmsAsnOpenApiController(TmsAsnEventConsumerApplicationService service){this.service=service;}@PostMapping("/events")public ApiResponse<Void> consume(@Valid @RequestBody Request body,HttpServletRequest request){if(!"TMS".equals(request.getHeader("X-Source-System")))throw new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.FORBIDDEN,"来源系统必须是TMS");service.consume(new TmsAsnEvent(request.getHeader("X-Event-Code"),body.eventType(),body.asnId(),body.shipmentId(),body.waybillNo(),body.carrierCode(),body.node(),body.occurredAt(),body.exceptionCode(),body.exceptionReason(),body.sourceVersion()));return ApiResponse.success(null,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long asnId,Long shipmentId,String waybillNo,String carrierCode,String node,@NotNull OffsetDateTime occurredAt,String exceptionCode,String exceptionReason,@Positive long sourceVersion){}}
